module top_module(
    input       D,
    input       reset,
    input       RST, 
    output  reg Q,
    output  reg NQ
);always @(posedge reset or negedge RST) begin
        if (!RST) begin
            Q <= 0;
            NQ <= 1;
        end else begin
            Q <= D;
            NQ <= ~D;
        end
    end

endmodule
